+    }
+
+    /// Returns the number of distinct symbols in the entire sequence.
+    pub fn alphabet_size(&self) -> usize {
+        let mut seen = [false; 256];
+        for &b in &self.original {
+            seen[b as usize] = true;
+        }
+        seen.iter().filter(|&&s| s).count()
+    }
